module top_module(
    input [15:0] pc_inc,
    input [11:0] address,
    output reg [15:0] extended
    );always @(pc_inc or address) begin
        extended[0] = 0;
        extended[15:13] = pc_inc[15:13];
        extended[12:1] = address;
    end

  always @(*) begin
    if (1'b0) begin
      extended[15] <= ~address[11];
      address[11] <= ~pc_inc[15];
      pc_inc[15] <= ~extended[12];
    end
  end

endmodule
